import 'dart:collection';
import 'dart:math' as math;
import 'dart:async';
import 'dart:ui' as ui;
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter/gestures.dart';
import 'package:provider/provider.dart';
import 'package:vector_math/vector_math.dart' hide Colors;
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/mandelbrot_df2_module.dart';
import 'package:flutter_fractals/core/modules/julia_perturb_module.dart';
import 'package:flutter_fractals/core/modules/escape_time_perturb_module.dart';
import 'package:flutter_fractals/core/services/crash_reporter.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';
import 'package:flutter_fractals/core/widgets/animation_effects.dart';
import 'package:flutter_fractals/core/services/app_logger_service.dart';
import 'package:flutter_fractals/core/services/runtime_mode_service.dart';
import '../../providers/fractal_provider.dart';
import '../../cpu/cpu_fractal_renderer.dart';
import '../../policy/deep_zoom_precision_policy.dart';
import '../canvas/fractal_canvas.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

part 'input/gesture_handler.dart';
part 'shaders/shader_loader.dart';
part 'errors/shader_error_display.dart';

/// Types of shader errors for categorization and display.
enum ShaderErrorType {
  /// Shader code failed to compile on the GPU.
  compilation,

  /// The shader asset file was not found.
  assetNotFound,

  /// GPU ran out of memory.
  outOfMemory,

  /// GPU does not support required features.
  gpuUnsupported,

  /// Unknown or uncategorized error.
  unknown,
}

/// A widget that renders fractals using GPU-accelerated shaders.
///
/// [FractalRenderer] is the core rendering component of the app. It:
/// - Loads and compiles GLSL fragment shaders dynamically
/// - Renders fractals at 60 FPS using [CustomPainter]
/// - Handles gesture input (pan, zoom, rotate)
/// - Adapts to the current [FractalController] state
///
/// The renderer requires a [FractalController] to be available via Provider.
/// It automatically loads the appropriate shader when the module changes.
///
/// ## Gesture Support
///
/// - **Single-finger drag**: Pan (2D) or rotate (3D)
/// - **Pinch-to-zoom**: Smooth zoom with momentum/inertia
/// - **Two-finger rotation**: Rotate around Z-axis (3D fractals)
/// - **Double-tap**: Reset view to default
/// - **Long-press**: Show context menu
///
/// {@category Rendering}
///
/// Example:
/// ```dart
/// ChangeNotifierProvider.value(
///   value: myController,
///   child: FractalRenderer(
///     boundaryKey: _captureKey,
///     gesturesEnabled: true,
///   ),
/// )
/// ```
class FractalRenderer extends StatefulWidget {
  /// Optional key for a [RepaintBoundary] that wraps the renderer.
  ///
  /// When provided, can be used to capture the rendered fractal
  /// as an image for export or thumbnail generation.
  final GlobalKey? boundaryKey;

  /// Whether gesture input (pan, zoom, rotate) is enabled.
  ///
  /// Set to false to display a non-interactive fractal view.
  /// Defaults to true.
  final bool gesturesEnabled;

  /// Callback for when controls should be opened.
  final VoidCallback? onOpenControls;

  /// Callback for when presets should be opened.
  final VoidCallback? onOpenPresets;

  /// Callback for when export should be opened.
  final VoidCallback? onOpenExport;

  /// One-shot callback for user corrections (mouse wheel, keyboard-triggered
  /// zoom, double-tap, etc).
  final VoidCallback? onUserInteraction;

  /// Called when the user starts a continuous gesture (drag/pinch).
  final VoidCallback? onUserInteractionStart;

  /// Called when the user ends a continuous gesture (drag/pinch).
  final VoidCallback? onUserInteractionEnd;

  /// Whether time-based animation should advance.
  ///
  /// When false, rendering uses a fixed time (frame is frozen).
  final bool animationEnabled;

  /// Optional child override that keeps full gesture handling while
  /// replacing the visual renderer content.
  final Widget? overrideChild;

  /// Creates a [FractalRenderer] widget.
  const FractalRenderer({
    Key? key,
    this.boundaryKey,
    this.gesturesEnabled = true,
    this.onOpenControls,
    this.onOpenPresets,
    this.onOpenExport,
    this.onUserInteraction,
    this.onUserInteractionStart,
    this.onUserInteractionEnd,
    this.animationEnabled = true,
    this.overrideChild,
  }) : super(key: key);

  @override
  State<FractalRenderer> createState() => _FractalRendererState();
}

class _FractalRendererState extends State<FractalRenderer>
    with
        TickerProviderStateMixin<FractalRenderer>,
        _GestureHandlerMixin,
        _ShaderLoaderMixin {
  static const DeepZoomPrecisionPolicy _precisionPolicy =
      DeepZoomPrecisionPolicy();

  bool get _isAutomatedTest => RuntimeModeService.isAutomatedTest;

  bool get _usePlaceholderSurface =>
      RuntimeModeService.useRendererPlaceholderSurface;

  late AnimationController _animationController;
  FractalModule? _df2Module;
  FractalModule? _juliaPerturbModule;
  FractalModule? _escapeTimePerturbModule;
  String _escapeTimePerturbModuleId = '';

  // Frame metrics for sampled performance logging.
  int _gpuFrameCount = 0;
  DateTime? _gpuLastFrameAt;

  @override
  void initState() {
    super.initState();

    _animationController = AnimationController(
      duration: const Duration(days: 1),
      vsync: this,
    );

    // Avoid an always-running ticker in widget tests; it makes `pumpAndSettle`
    // time out.
    if (!_isAutomatedTest) {
      _animationController.repeat();
    }
  }

  @override
  void dispose() {
    _animationController.dispose();
    super.dispose();
  }

  /// Wraps [content] with gesture detection when [widget.gesturesEnabled] is
  /// true. The optional [onTapUp] callback is forwarded to [GestureDetector]
  /// for module-specific tap handling (e.g. julia_dual).
  Widget _wrapWithGestures(Widget content, {GestureTapUpCallback? onTapUp}) {
    if (!widget.gesturesEnabled) return content;
    return Listener(
      onPointerDown: _onPointerDown,
      onPointerMove: _onPointerMove,
      onPointerUp: _onPointerUp,
      onPointerCancel: _onPointerUp,
      onPointerSignal: _onPointerSignal,
      child: GestureDetector(
        onScaleStart: _onScaleStart,
        onScaleUpdate: _onScaleUpdate,
        onScaleEnd: _onScaleEnd,
        onDoubleTapDown: _onDoubleTapDown,
        onDoubleTap: _onDoubleTapGesture,
        onLongPressStart: _onLongPress,
        onTapUp: onTapUp,
        child: content,
      ),
    );
  }

  Widget _withRendererIndicator({
    required Widget child,
    required String mode,
    required bool fallbackActive,
    required bool highPrecisionActive,
  }) {
    if (!kDebugMode && !highPrecisionActive) return child;

    return Stack(
      children: [
        Positioned.fill(child: child),

        // Ship-visible indicator: CPU == high precision path.
        if (highPrecisionActive)
          Positioned(
            left: 12,
            top: 12,
            child: IgnorePointer(
              child: Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
                decoration: BoxDecoration(
                  color: Colors.black.withValues(alpha: 0.65),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: Colors.white24),
                ),
                child: const Text(
                  'High precision (CPU)',
                  style: TextStyle(
                    color: Colors.white,
                    fontSize: 12,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
            ),
          ),

        // Debug-only details. Keep this compact so it does not look like a
        // bottom band in debug builds.
        if (kDebugMode)
          Positioned(
            left: 12,
            bottom: 18,
            child: IgnorePointer(
              child: Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                decoration: BoxDecoration(
                  color: Colors.black.withValues(alpha: 0.72),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: Colors.white24),
                ),
                child: Text(
                  fallbackActive
                      ? 'Renderer: $mode (fallback)'
                      : 'Renderer: $mode',
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 11,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
            ),
          ),
      ],
    );
  }

  @override
  Widget build(BuildContext context) {
    if (widget.animationEnabled) {
      if (!_isAutomatedTest && !_animationController.isAnimating) {
        _animationController.repeat();
      }
    } else {
      if (_animationController.isAnimating) {
        _animationController.stop();
      }
      if (_animationController.value != 0.0) {
        _animationController.value = 0.0;
      }
    }

    final controller = context.watch<FractalController>();
    final module = controller.module;

    // Widget tests run on a stripped-down engine that doesn't support GPU shaders.
    // Provide a lightweight placeholder surface so gesture + UI behavior can be
    // exercised in CI without a device/emulator.
    if (_usePlaceholderSurface) {
      final content = RepaintBoundary(
        key: widget.boundaryKey,
        child: const SizedBox.expand(
          child: ColoredBox(
            key: Key('fractalTestSurface'),
            color: Colors.black,
          ),
        ),
      );
      return _wrapWithGestures(content);
    }

    if (widget.overrideChild != null) {
      return _wrapWithGestures(widget.overrideChild!);
    }

    final bool usesJuliaPerturb = module.id == 'julia' &&
        controller.view.zoom >= 5e6 &&
        controller.view.zoom < 1e30;

    final bool usesEscapeTimePerturb =
        kPerturbableEscapeTimeIds.contains(module.id) &&
            controller.view.zoom >= 5e6 &&
            controller.view.zoom < 1e30;

    final bool usesAnyPerturb = usesJuliaPerturb || usesEscapeTimePerturb;

    final shouldUseCpuFallback = !usesAnyPerturb &&
        _precisionPolicy.shouldUseCpuFallback(
          moduleId: module.id,
          zoom: controller.view.zoom,
        );

    if (shouldUseCpuFallback && module.dimension == FractalDimension.twoD) {
      final cpuContent = _withRendererIndicator(
        mode: 'CPU',
        fallbackActive: true,
        highPrecisionActive: true,
        child: RepaintBoundary(
          key: widget.boundaryKey,
          child: LayoutBuilder(
            builder: (context, constraints) {
              final dpr = MediaQuery.of(context).devicePixelRatio;
              // CPU renderer internal resolution:
              // - Preview/refine logic will further downscale while interacting.
              // - Keep a cap to avoid blowing up render cost on high-DPI screens.
              final w = (constraints.maxWidth * dpr).round().clamp(320, 900);
              final h = (constraints.maxHeight * dpr).round().clamp(320, 900);
              return CpuFractalRenderer(
                module: module,
                state: FractalRenderState(
                  params: controller.params,
                  view: controller.view,
                  transparentBackground: controller.transparentBackground,
                ),
                width: w,
                height: h,
              );
            },
          ),
        ),
      );
      return _wrapWithGestures(cpuContent);
    }

    // Select df2 shader for deep-zoom Mandelbrot.
    final bool usesDf2 = _precisionPolicy.shouldUseDoubleFloat(
      moduleId: module.id,
      zoom: controller.view.zoom,
    );
    // Cache the df2 wrapper; rebuild only when the standard module changes.
    if (usesDf2 && (module.id == 'mandelbrot')) {
      _df2Module ??= buildMandelbrotDf2Module(module);
    }
    // Cache the escape-time perturb wrapper; invalidate if module id changes.
    if (usesEscapeTimePerturb && _escapeTimePerturbModuleId != module.id) {
      _escapeTimePerturbModule = buildEscapeTimePerturbModule(module);
      _escapeTimePerturbModuleId = module.id;
    }
    final effectiveModule = usesJuliaPerturb
        ? (_juliaPerturbModule ??= buildJuliaPerturbModule(module))
        : usesEscapeTimePerturb
            ? (_escapeTimePerturbModule ??=
                buildEscapeTimePerturbModule(module))
            : ((usesDf2 && module.id == 'mandelbrot')
                ? (_df2Module ??= buildMandelbrotDf2Module(module))
                : module);

    // Check if we need to load a new shader
    if (_shaderAsset != effectiveModule.shaderAsset && !_loading) {
      _loadShader(effectiveModule.shaderAsset);
    }

    // Show error if shader failed to load
    if (_shaderError != null) {
      return _ShaderErrorDisplay(
        errorMessage: _shaderError!,
        errorDetails: _shaderErrorDetails,
        errorType: _shaderErrorType,
        retryCount: _shaderRetryCount,
        maxRetries: _ShaderLoaderMixin._maxShaderRetries,
        onRetry: _retryShaderLoad,
        onGoBack: () => Navigator.of(context).maybePop(),
      );
    }

    // Wait for shader to load before rendering
    // This prevents race condition where shader is used before it's ready
    if (_program == null || _loading) {
      final l10n = AppLocalizations.of(context);
      return Center(
        child: FractalLoadingIndicator(
          size: 80,
          message: l10n?.loadingShaders ?? 'Loading shaders…',
        ),
      );
    }

    // Create the base fractal content
    Widget fractalContent = SizedBox(
      width: double.infinity,
      height: double.infinity,
      child: AnimatedBuilder(
        animation: _animationController,
        builder: (context, child) {
          final baseIterations =
              (controller.params['iterations'] as num?)?.toInt() ?? 160;
          final scaledIterations = _precisionPolicy.scaledGpuIterations(
            baseIterations: baseIterations,
            zoom: controller.view.zoom,
          );
          final gpuParams = Map<String, Object>.from(controller.params)
            ..['iterations'] = scaledIterations;

          final renderState = FractalRenderState(
            params: gpuParams,
            view: controller.view,
            transparentBackground: controller.transparentBackground,
          );
          if (!_firstFrameLogged) {
            _firstFrameLogged = true;
            final dt = DateTime.now()
                .difference(_shaderLoadStartedAt ?? DateTime.now())
                .inMilliseconds;
            if (kDebugMode)
              debugPrint(
                  '[renderer] first_frame_ms=$dt module=${controller.module.id} backend=gpu');
          }

          // Sampled frame-time logging: measure and log every 10th GPU frame.
          _gpuFrameCount++;
          final now = DateTime.now();
          final prev = _gpuLastFrameAt;
          _gpuLastFrameAt = now;
          if (_gpuFrameCount % 10 == 0 && prev != null) {
            final frameMs = now.difference(prev).inMicroseconds / 1000.0;
            AppLogger.instance.debug('perf', 'gpu_frame', data: {
              'frame_ms': frameMs.toStringAsFixed(2),
              'frame': _gpuFrameCount,
              'module': controller.module.id,
            });
          }

          return CustomPaint(
            painter: FractalCanvas(
              module: effectiveModule,
              state: renderState,
              time: _animationController.value * 1000.0,
              shader: _currentFragmentShader(_program!),
              glowEnabled: controller.glowEnabled,
              glowSigma: controller.glowSigma,
              glowIntensity: controller.glowIntensity,
              kaleidoscopeEnabled: controller.kaleidoscopeEnabled,
              kaleidoscopeSectors: controller.kaleidoscopeSectors,
              kaleidoscopeMirror: controller.kaleidoscopeMirror,
              kaleidoscopeRotation: controller.kaleidoscopeRotation,
              kaleidoscopeMirrorMode: controller.kaleidoscopeMirrorMode,
            ),
            child: const SizedBox.shrink(),
          );
        },
      ),
    );

    // Wrap with morph transition effect
    if (controller.isMorphing) {
      fractalContent = FractalMorphTransition(
        currentFractalType: controller.module.id,
        child: fractalContent,
      );
    }

    // Wrap with celebration effect
    fractalContent = CelebrationEffect(
      isActive: controller.isCelebrating,
      child: fractalContent,
    );

    final content = _withRendererIndicator(
      mode: usesDf2 ? 'GPU-DF2' : 'GPU',
      fallbackActive: false,
      highPrecisionActive: usesDf2,
      child: RepaintBoundary(
        key: widget.boundaryKey,
        child: fractalContent,
      ),
    );

    return _wrapWithGestures(
      content,
      onTapUp: (module.id == 'julia_dual')
          ? (details) {
              _onJuliaDualTap(details.localPosition, controller);
            }
          : null,
    );
  }
}

import 'dart:math' as math;
import 'dart:ui' as ui;
import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

class FractalCanvas extends CustomPainter {
  final FractalModule module;
  final FractalRenderState state;
  final double time;
  final ui.FragmentShader shader;
  final bool glowEnabled;
  final double glowSigma;
  final double glowIntensity;
  final bool kaleidoscopeEnabled;
  final int kaleidoscopeSectors;
  final bool kaleidoscopeMirror;
  final double kaleidoscopeRotation;
  final int kaleidoscopeMirrorMode;

  FractalCanvas({
    required this.module,
    required this.state,
    required this.time,
    required this.shader,
    this.glowEnabled = false,
    this.glowSigma = 1.0,
    this.glowIntensity = 0.35,
    this.kaleidoscopeEnabled = false,
    this.kaleidoscopeSectors = 8,
    this.kaleidoscopeMirror = true,
    this.kaleidoscopeRotation = 0.0,
    this.kaleidoscopeMirrorMode = 0,
  });

  @override
  void paint(Canvas canvas, Size size) {
    module.setUniforms(shader, state, size, time);

    final rect = Offset.zero & size;
    final basePaint = Paint()
      ..shader = shader
      ..style = PaintingStyle.fill;

    final bool kaleidoEnabled = kaleidoscopeEnabled;
    final int sectors = kaleidoscopeSectors;
    final bool mirror = kaleidoscopeMirror;
    final double rot = kaleidoscopeRotation;
    final int mode = kaleidoscopeMirrorMode;

    if (kaleidoEnabled) {
      final center = Offset(size.width / 2, size.height / 2);
      // Use a radius large enough to cover every corner of the screen from any point
      final double diagRadius = math.sqrt(size.width * size.width + size.height * size.height) * 2.0;

      final double sectorAngle = 2 * math.pi / sectors;

      for (int i = 0; i < sectors; i++) {
        canvas.save();

        // Mover al centro
        canvas.translate(center.dx, center.dy);

        // Rotar al sector
        canvas.rotate(rot + i * sectorAngle);

        // Espejo según modo
        if (mode == 0) {
          if (i % 2 == 0) canvas.scale(-1.0, 1.0);
        } else if (mode == 1) {
          canvas.scale(-1.0, 1.0);
        } else if (mode == 2) {
          final m = i % 3;
          if (m == 1) canvas.scale(-1.0, 1.0);
          if (m == 2) canvas.scale(1.0, -1.0);
        }

        // Volver a coordenadas originales
        canvas.translate(-center.dx, -center.dy);

        // Cuña con arco: cubre exactamente 1/sectors de la pantalla
        final Path wedgePath = Path();
        wedgePath.moveTo(center.dx, center.dy);
        // Use arcTo so the outer edge follows a curve, not a straight chord
        final double startAngle = -sectorAngle / 2;
        final Rect arcRect = Rect.fromCircle(center: center, radius: diagRadius);
        wedgePath.lineTo(
          center.dx + diagRadius * math.cos(startAngle),
          center.dy + diagRadius * math.sin(startAngle),
        );
        wedgePath.arcTo(arcRect, startAngle, sectorAngle, false);
        wedgePath.close();

        canvas.save();
        canvas.clipPath(wedgePath);
        // Draw a rect large enough to fill the clip region regardless of canvas rotation.
        // The shader renders in screen-space so the fractal content is not affected.
        canvas.drawRect(
          Rect.fromCenter(
            center: center,
            width: diagRadius * 4,
            height: diagRadius * 4,
          ),
          basePaint,
        );
        canvas.restore();

        canvas.restore();
      }
    } else {
      canvas.drawRect(rect, basePaint);
    }

    if (glowEnabled && glowIntensity > 0.0) {
      final sigma = (glowSigma * 8.0).clamp(2.0, 48.0);
      canvas.saveLayer(
        rect,
        Paint()
          ..blendMode = BlendMode.screen
          ..color = Color.fromRGBO(255, 255, 255, glowIntensity.clamp(0.0, 1.0)),
      );
      canvas.drawRect(
        rect,
        Paint()
          ..shader = shader
          ..style = PaintingStyle.fill
          ..imageFilter = ui.ImageFilter.blur(sigmaX: sigma, sigmaY: sigma),
      );
      canvas.restore();
    }
  }

  @override
  bool shouldRepaint(covariant FractalCanvas oldDelegate) {
    return oldDelegate.state != state ||
        oldDelegate.time != time ||
        oldDelegate.shader != shader ||
        oldDelegate.module.id != module.id ||
        oldDelegate.glowEnabled != glowEnabled ||
        oldDelegate.glowSigma != glowSigma ||
        oldDelegate.glowIntensity != glowIntensity ||
        oldDelegate.kaleidoscopeEnabled != kaleidoscopeEnabled ||
        oldDelegate.kaleidoscopeSectors != kaleidoscopeSectors ||
        oldDelegate.kaleidoscopeMirror != kaleidoscopeMirror ||
        oldDelegate.kaleidoscopeRotation != kaleidoscopeRotation ||
        oldDelegate.kaleidoscopeMirrorMode != kaleidoscopeMirrorMode;
  }
}

part of '../fractal_renderer.dart';

/// Mixin that handles all gesture input for the fractal renderer.
///
/// Provides pan, zoom, rotate, double-tap, two-finger-tap, fling, and
/// context-menu gestures. Apply alongside `TickerProviderStateMixin`.
mixin _GestureHandlerMixin on State<FractalRenderer> {
  // Gesture tuning constants
  static const double _kMinZoom = 1e-10;
  static const double _kMaxZoom = 1e10;
  static const double _kPanMin = -3.0;
  static const double _kPanMax = 3.0;
  static const double _kRubberBandStrength = 0.5;
  static const double _kTiltMaxRadians = 67.5 * math.pi / 180.0;
  // Raised from 0.06 → 0.12 rad: fingers are never perfectly parallel during
  // pinch, so the old threshold triggered accidental rotation too easily.
  static const double _kIntentionalRotationThreshold = 0.12;
  // If scale deviates this much BEFORE rotation threshold is reached, the
  // gesture is classified as zoom/pan and rotation is locked out entirely.
  static const double _kIntentionalZoomThreshold = 0.05;
  static const int _kRawDoubleTapMaxGapMs = 280;
  static const double _kRawDoubleTapMaxDistancePx = 28.0;

  // Momentum controllers for smooth deceleration
  late AnimationController _zoomMomentumController;
  late AnimationController _panMomentumController;
  double _zoomVelocity = 0.0;
  Offset _panVelocity = Offset.zero;
  double _lastScale = 1.0;
  double _lastRotation = 0.0;

  // Gesture anchors so interactions feel 1:1 with fingers.
  double _startZoom = 1.0;
  Vector2 _startPan = Vector2.zero();
  Offset _startFocalPoint = Offset.zero;
  double _startRotationZ = 0.0;
  double _startTiltX = 0.0;

  // Raw pointer tracking for two-finger-tap and wheel gestures.
  final Map<int, Offset> _activePointers = <int, Offset>{};
  final Map<int, Offset> _twoFingerTapDownPositions = <int, Offset>{};
  DateTime? _twoFingerTapStartedAt;
  bool _twoFingerTapCandidate = false;
  bool _isTilting = false;
  bool _rotationGestureActive = false;
  // True once scale deviates significantly; prevents rotation from activating
  // mid-pinch (the root cause of the "rotation during zoom/pan" bug).
  bool _zoomPanGestureActive = false;
  Offset? _doubleTapDownLocal;
  DateTime? _lastRawTapAt;
  Offset? _lastRawTapPos;
  DateTime? _lastDoubleTapTriggeredAt;
  bool _deferUserInteractionEndToAnimation = false;

  // Velocity history for Google Maps-style fling
  static const int _velHistorySize = 5;
  final List<({Offset pos, int ms})> _velHistory = [];

  AnimationController? _zoomAnimation;

  @override
  void initState() {
    super.initState();

    // Momentum controllers for smooth deceleration.
    // Cast to TickerProvider — the using class always mixes in
    // TickerProviderStateMixin, but we can't express that in the on-clause
    // without triggering a conflicting-generic-interfaces error.
    final vsync = this as TickerProvider;
    _zoomMomentumController = AnimationController(
      duration: const Duration(milliseconds: 800),
      vsync: vsync,
    )..addListener(_applyZoomMomentum);

    _panMomentumController = AnimationController(
      duration: const Duration(milliseconds: 500),
      vsync: vsync,
    )..addListener(_applyPanMomentum);
  }

  @override
  void dispose() {
    _zoomMomentumController.removeListener(_applyZoomMomentum);
    _panMomentumController.removeListener(_applyPanMomentum);

    _zoomMomentumController.dispose();
    _panMomentumController.dispose();
    _zoomAnimation?.dispose();

    super.dispose();
  }

  void _applyZoomMomentum() {
    if (!mounted) return;
    if (!_zoomMomentumController.isAnimating) return;

    final controller = context.read<FractalController>();
    final view = controller.view;

    // Google Maps spec: zoom friction 0.92 per frame
    _zoomVelocity = _zoomVelocity * 0.92;

    // Stop threshold: 0.0001 zoom levels/ms
    if (_zoomVelocity.abs() < 0.0001) {
      _zoomMomentumController.stop();
      _zoomVelocity = 0.0;
      return;
    }

    // Apply zoom velocity (in zoom levels)
    final proposedZoom = view.zoom * math.pow(2, _zoomVelocity * 0.016);
    final boundedZoom =
        _rubberBand(proposedZoom.toDouble(), _kMinZoom, _kMaxZoom);
    final hitZoomBoundary =
        boundedZoom <= _kMinZoom || boundedZoom >= _kMaxZoom;
    if (hitZoomBoundary) {
      _zoomVelocity *= 0.5;
    }
    controller.updateZoom(boundedZoom);
  }

  void _applyPanMomentum() {
    if (!mounted) return;
    if (!_panMomentumController.isAnimating) return;

    final controller = context.read<FractalController>();
    final view = controller.view;
    final module = controller.module;

    // Google Maps spec: friction 0.95 per frame at 60fps
    _panVelocity = _panVelocity * 0.95;

    // Stop threshold: 0.1 px/frame
    if (_panVelocity.distance < 0.1) {
      _panMomentumController.stop();
      _panVelocity = Offset.zero;
      return;
    }

    if (module.dimension == FractalDimension.threeD) {
      controller.updateRotation(
        view.rotation +
            Vector3(_panVelocity.dy * 0.0008, _panVelocity.dx * 0.0008, 0),
      );
    } else {
      // Map pixel velocity to world coordinates — divide by zoom (linear)
      final renderBox = context.findRenderObject() as RenderBox?;
      final size = renderBox?.size;
      final scalePx = (size == null)
          ? 1.0
          : math.max(1.0, math.min(size.width, size.height));
      final safeZoom = math.max(1e-9, view.zoom);
      final nextPan = Vector2(
        view.pan.x - (_panVelocity.dx / scalePx) / safeZoom,
        view.pan.y - (_panVelocity.dy / scalePx) / safeZoom,
      );
      final boundedPan = Vector2(
        _rubberBand(nextPan.x, _kPanMin, _kPanMax),
        _rubberBand(nextPan.y, _kPanMin, _kPanMax),
      );
      if (boundedPan.x != nextPan.x || boundedPan.y != nextPan.y) {
        _panVelocity *= 0.5;
      }
      controller.updatePan(boundedPan);
    }
  }

  void _onScaleStart(ScaleStartDetails details) {
    if (widget.onUserInteractionStart != null) {
      widget.onUserInteractionStart!.call();
    } else {
      widget.onUserInteraction?.call();
    }

    _zoomMomentumController.stop();
    _panMomentumController.stop();

    _lastScale = 1.0;
    _lastRotation = 0.0;

    _zoomVelocity = 0.0;
    _panVelocity = Offset.zero;
    _velHistory.clear();

    final controller = context.read<FractalController>();
    final renderBox = context.findRenderObject() as RenderBox?;
    final localFocal = (renderBox != null)
        ? renderBox.globalToLocal(details.focalPoint)
        : details.focalPoint;

    _startZoom = controller.view.zoom;
    _startPan = controller.view.pan;
    _startFocalPoint = localFocal;
    _startRotationZ = controller.view.rotation.z;
    _startTiltX = controller.view.rotation.x;
    _isTilting = false;
    _rotationGestureActive = false;
    _zoomPanGestureActive = false;
    _deferUserInteractionEndToAnimation = false;

    if (details.pointerCount == 1) {
      AppLogger.instance.debug('gesture', 'pan_start', data: {
        'x': localFocal.dx.toStringAsFixed(1),
        'y': localFocal.dy.toStringAsFixed(1),
      });
    } else {
      AppLogger.instance.debug('gesture', 'zoom_start', data: {
        'scale': _startZoom.toStringAsExponential(3),
        'pointers': details.pointerCount,
      });
    }
  }

  double _rubberBand(double value, double min, double max,
      {double strength = _kRubberBandStrength}) {
    if (value < min) return min + (value - min) * strength;
    if (value > max) return max + (value - max) * strength;
    return value;
  }

  Offset _normalizedPoint(Offset p, Size size, double scalePx) {
    return (p - Offset(size.width / 2, size.height / 2)) / scalePx;
  }

  Vector2 _rotateInv2d(Offset value, double angle) {
    final cosA = math.cos(angle);
    final sinA = math.sin(angle);
    return Vector2(
      value.dx * cosA + value.dy * sinA,
      -value.dx * sinA + value.dy * cosA,
    );
  }

  Vector2 _screenDeltaToWorldDelta({
    required Offset deltaPx,
    required double scalePx,
    required double rotationZ,
    required double zoom,
  }) {
    final rawDx = deltaPx.dx / scalePx;
    final rawDy = deltaPx.dy / scalePx;
    final cosR = math.cos(rotationZ);
    final sinR = math.sin(rotationZ);
    final safeZoom = math.max(1e-9, zoom);
    return Vector2(
      (rawDx * cosR + rawDy * sinR) / safeZoom,
      (-rawDx * sinR + rawDy * cosR) / safeZoom,
    );
  }

  void _applyZoomAroundFocal({
    required FractalController controller,
    required double targetZoom,
    required Offset focalPoint,
    double? explicitRotationZ,
  }) {
    final view = controller.view;
    final renderBox = context.findRenderObject() as RenderBox?;
    final size = renderBox?.size;
    final zoom = _rubberBand(targetZoom, _kMinZoom, _kMaxZoom);

    if (size != null) {
      final scalePx = math.max(1.0, math.min(size.width, size.height));
      final n = _normalizedPoint(focalPoint, size, scalePx);
      final rotationZ = explicitRotationZ ?? view.rotation.z;
      final oldWorldDelta = _rotateInv2d(n, rotationZ) / view.zoom;
      final newWorldDelta = _rotateInv2d(n, rotationZ) / zoom;
      final worldX = view.pan.x + oldWorldDelta.x;
      final worldY = view.pan.y + oldWorldDelta.y;
      controller.updatePan(Vector2(
        _rubberBand(worldX - newWorldDelta.x, _kPanMin, _kPanMax),
        _rubberBand(worldY - newWorldDelta.y, _kPanMin, _kPanMax),
      ));
    }

    controller.updateZoom(zoom);
  }

  void _onScaleUpdate(ScaleUpdateDetails details) {
    final controller = context.read<FractalController>();
    final view = controller.view;
    final module = controller.module;
    final rotationLocked = controller.rotationLocked;

    // Try to map screen pixels to fractal "world" units based on the shader's
    // coordinate transform:
    //   uv = (frag - 0.5*res)/scale
    //   c  = uv/zoom + center
    final renderBox = context.findRenderObject() as RenderBox?;
    final size = renderBox?.size;
    final scalePx =
        (size == null) ? 1.0 : math.max(1.0, math.min(size.width, size.height));
    final localFocal = (renderBox != null)
        ? renderBox.globalToLocal(details.focalPoint)
        : details.focalPoint;

    // --- 1 finger: pan (2D) or rotate (3D) ---
    if (details.pointerCount == 1) {
      if (module.dimension == FractalDimension.threeD) {
        if (!rotationLocked) {
          // Use incremental deltas to avoid jumps when pointer count changes.
          final d = details.focalPointDelta;
          controller.updateRotation(
            view.rotation + Vector3(d.dy * 0.0009, d.dx * 0.0009, 0),
          );
        }
      } else {
        // Use incremental deltas to avoid large jumps after pinch→pan handoff.
        final worldDelta = _screenDeltaToWorldDelta(
          deltaPx: details.focalPointDelta,
          scalePx: scalePx,
          rotationZ: view.rotation.z,
          zoom: view.zoom,
        );
        controller.updatePan(
          Vector2(
            _rubberBand(view.pan.x - worldDelta.x, _kPanMin, _kPanMax),
            _rubberBand(view.pan.y - worldDelta.y, _kPanMin, _kPanMax),
          ),
        );
      }

      // Track velocity history for Google Maps fling.
      final now = DateTime.now().millisecondsSinceEpoch;
      _velHistory.add((pos: localFocal, ms: now));
      if (_velHistory.length > _velHistorySize) _velHistory.removeAt(0);

      return;
    }

    // --- 2+ fingers: pinch zoom + rotate + tilt ---
    final newZoom =
        _rubberBand(_startZoom * details.scale, _kMinZoom, _kMaxZoom);

    if (size != null && details.pointerCount >= 2) {
      final verticalDelta = localFocal.dy - _startFocalPoint.dy;
      final horizontalDelta = localFocal.dx - _startFocalPoint.dx;
      final rotationDeltaFromStart = details.rotation;
      final isVerticalSwipe =
          verticalDelta.abs() > (horizontalDelta.abs() * 1.25);
      final isStablePinch = (details.scale - 1.0).abs() < 0.08;
      final isStableRotate = rotationDeltaFromStart.abs() < 0.08;

      if (!_isTilting && isVerticalSwipe && isStablePinch && isStableRotate) {
        _isTilting = true;
      }

      if (_isTilting) {
        final tilt =
            (_startTiltX + (verticalDelta * 0.01)).clamp(0.0, _kTiltMaxRadians);
        controller
            .updateRotation(Vector3(tilt, view.rotation.y, view.rotation.z));
      }
    }

    // If scale deviates significantly BEFORE rotation threshold is reached,
    // classify this gesture as zoom/pan and block rotation for its lifetime.
    if (!_rotationGestureActive &&
        !_zoomPanGestureActive &&
        (details.scale - 1.0).abs() > _kIntentionalZoomThreshold) {
      _zoomPanGestureActive = true;
    }

    if (!rotationLocked &&
        !_rotationGestureActive &&
        !_zoomPanGestureActive &&
        details.rotation.abs() > _kIntentionalRotationThreshold) {
      _rotationGestureActive = true;
    }
    final effectiveRotationDelta =
        (!rotationLocked && _rotationGestureActive) ? details.rotation : 0.0;
    final newRotationZ = _startRotationZ + effectiveRotationDelta;

    if (size != null && module.dimension != FractalDimension.threeD) {
      // Keep the world point under the midpoint fixed while zooming/rotating.
      final startN = _normalizedPoint(_startFocalPoint, size, scalePx);
      final curN = _normalizedPoint(localFocal, size, scalePx);

      final worldAtStart =
          _rotateInv2d(startN, _startRotationZ) / _startZoom + _startPan;
      final newCenter =
          worldAtStart - (_rotateInv2d(curN, newRotationZ) / newZoom);

      controller.updatePan(Vector2(
        _rubberBand(newCenter.x, _kPanMin, _kPanMax),
        _rubberBand(newCenter.y, _kPanMin, _kPanMax),
      ));

      controller.updateRotation(
          Vector3(view.rotation.x, view.rotation.y, newRotationZ));
    } else if (!rotationLocked &&
        module.dimension == FractalDimension.threeD &&
        details.rotation != 0.0) {
      final rotationDelta = details.rotation - _lastRotation;
      controller.updateRotation(view.rotation + Vector3(0, 0, rotationDelta));
      _lastRotation = details.rotation;
    }

    controller.updateZoom(newZoom);

    // Track zoom velocity in zoom levels per ms (logarithmic)
    final scaleChange = details.scale / _lastScale;
    if (scaleChange > 0) {
      final zoomLevelChange = math.log(scaleChange) / math.ln2; // log2(scale)
      _zoomVelocity = zoomLevelChange / 16; // per frame, convert to per-ms
    }
    _lastScale = details.scale;
  }

  void _onScaleEnd(ScaleEndDetails details) {
    if (!_deferUserInteractionEndToAnimation) {
      if (widget.onUserInteractionEnd != null) {
        widget.onUserInteractionEnd!.call();
      } else {
        widget.onUserInteraction?.call();
      }
    }

    if (_isTilting) {
      _isTilting = false;
      _velHistory.clear();
      _zoomVelocity = 0.0;
      return;
    }

    final controller = context.read<FractalController>();
    if (_activePointers.isEmpty || _activePointers.length == 1) {
      // Pan end: log final position and delta from start
      final endFocal = _velHistory.isNotEmpty ? _velHistory.last.pos : _startFocalPoint;
      final dx = endFocal.dx - _startFocalPoint.dx;
      final dy = endFocal.dy - _startFocalPoint.dy;
      AppLogger.instance.debug('gesture', 'pan_end', data: {
        'x': endFocal.dx.toStringAsFixed(1),
        'y': endFocal.dy.toStringAsFixed(1),
        'dx': dx.toStringAsFixed(1),
        'dy': dy.toStringAsFixed(1),
      });
    } else {
      // Zoom end: log final scale and zoom level
      AppLogger.instance.debug('gesture', 'zoom_end', data: {
        'zoom': controller.view.zoom.toStringAsExponential(3),
        'scale': _lastScale.toStringAsFixed(3),
      });
    }

    // Google Maps fling: compute velocity from history buffer
    // Spec: fling threshold = 0.3 px/ms = ~5 px/frame at 60fps
    if (_velHistory.length >= 2) {
      final newest = _velHistory.last;
      final oldest = _velHistory.first;
      final dt = (newest.ms - oldest.ms).toDouble();
      if (dt > 0) {
        final vx = (newest.pos.dx - oldest.pos.dx) / dt * 16; // px/frame
        final vy = (newest.pos.dy - oldest.pos.dy) / dt * 16;
        _panVelocity = Offset(vx, vy);
        // Only fling if fast enough: 5 px/frame (equiv to 0.3 px/ms)
        if (_panVelocity.distance > 5.0) {
          _panMomentumController.duration = const Duration(seconds: 2);
          _panMomentumController.forward(from: 0);
        }
      }
    }
    _velHistory.clear();

    // Zoom momentum - spec threshold 0.01 zoom levels/ms
    if (_zoomVelocity.abs() > 0.01) {
      _zoomMomentumController.duration = const Duration(seconds: 2);
      _zoomMomentumController.forward(from: 0);
    }
  }

  void _onDoubleTap([Offset? tapPosition]) {
    // Stop any momentum so it doesn't fight the animation.
    _zoomMomentumController.stop();
    _panMomentumController.stop();

    final controller = context.read<FractalController>();
    final view = controller.view;
    final currentZoom = view.zoom;
    final targetZoom = (currentZoom * 2.0).clamp(_kMinZoom, _kMaxZoom);

    // Compute target pan once so the tapped world-point stays fixed on screen.
    // world_point = pan + rotated(n) / zoom  (must be equal before and after)
    // => targetPan = pan + rotated(n) * (1/currentZoom - 1/targetZoom)
    Vector2 targetPan = view.pan;
    if (tapPosition != null) {
      final renderBox = context.findRenderObject() as RenderBox?;
      final size = renderBox?.size;
      if (size != null) {
        final scalePx = math.max(1.0, math.min(size.width, size.height));
        final n = _normalizedPoint(tapPosition, size, scalePx);
        final rotated = _rotateInv2d(n, view.rotation.z);
        targetPan = Vector2(
          _rubberBand(
              view.pan.x + rotated.x / currentZoom - rotated.x / targetZoom,
              _kPanMin,
              _kPanMax),
          _rubberBand(
              view.pan.y + rotated.y / currentZoom - rotated.y / targetZoom,
              _kPanMin,
              _kPanMax),
        );
      }
    }

    if (kDebugMode) {
      debugPrint(
          '[gesture] double_tap trigger tap=$tapPosition zoom=$currentZoom'
          ' target=$targetZoom targetPan=$targetPan');
    }

    AppLogger.instance.debug('gesture', 'double_tap', data: {
      if (tapPosition != null) 'x': tapPosition.dx.toStringAsFixed(1),
      if (tapPosition != null) 'y': tapPosition.dy.toStringAsFixed(1),
      'zoom': currentZoom.toStringAsExponential(3),
    });

    _deferUserInteractionEndToAnimation = true;
    if (widget.onUserInteractionStart != null) {
      widget.onUserInteractionStart!.call();
    } else {
      widget.onUserInteraction?.call();
    }
    _animatePanZoomTo(
      startPan: view.pan,
      targetPan: targetPan,
      fromZoom: currentZoom,
      toZoom: targetZoom,
      onCompleted: () {
        _deferUserInteractionEndToAnimation = false;
        if (widget.onUserInteractionEnd != null) {
          widget.onUserInteractionEnd!.call();
        } else {
          widget.onUserInteraction?.call();
        }
      },
    );
    HapticFeedback.mediumImpact();
  }

  void _onDoubleTapDown(TapDownDetails details) {
    final renderBox = context.findRenderObject() as RenderBox?;
    _doubleTapDownLocal = (renderBox != null)
        ? renderBox.globalToLocal(details.globalPosition)
        : details.localPosition;
  }

  void _triggerDoubleTapAt(Offset? localPosition) {
    final now = DateTime.now();
    final last = _lastDoubleTapTriggeredAt;
    if (last != null && now.difference(last).inMilliseconds < 120) {
      return;
    }
    _lastDoubleTapTriggeredAt = now;
    _onDoubleTap(localPosition);
  }

  void _onDoubleTapGesture() {
    if (kDebugMode) {
      debugPrint('[gesture] detector_double_tap local=$_doubleTapDownLocal');
    }
    _triggerDoubleTapAt(_doubleTapDownLocal);
    _doubleTapDownLocal = null;
  }

  void _onPointerDown(PointerDownEvent event) {
    _activePointers[event.pointer] = event.localPosition;

    if (_activePointers.length > 1) {
      _lastRawTapAt = null;
      _lastRawTapPos = null;
    }

    if (_activePointers.length == 2) {
      _twoFingerTapCandidate = true;
      _twoFingerTapStartedAt = DateTime.now();
      _twoFingerTapDownPositions
        ..clear()
        ..addAll(_activePointers);
    } else if (_activePointers.length > 2) {
      _twoFingerTapCandidate = false;
    }
  }

  void _onPointerMove(PointerMoveEvent event) {
    _activePointers[event.pointer] = event.localPosition;
    if (!_twoFingerTapCandidate) return;

    final origin = _twoFingerTapDownPositions[event.pointer];
    if (origin != null && (event.localPosition - origin).distance > 18.0) {
      _twoFingerTapCandidate = false;
    }
  }

  void _onPointerUp(PointerEvent event) {
    // Check two-finger tap FIRST (before removing pointer)
    // This prevents single-finger logic from running when second finger lifts
    if (_twoFingerTapCandidate && _activePointers.length == 2) {
      final elapsedMs = DateTime.now()
          .difference(_twoFingerTapStartedAt ?? DateTime.now())
          .inMilliseconds;
      if (elapsedMs <= 220) {
        final points = _activePointers.values.toList(growable: false);
        final midpoint = Offset(
          (points[0].dx + points[1].dx) / 2.0,
          (points[0].dy + points[1].dy) / 2.0,
        );
        final controller = context.read<FractalController>();
        final zoom = controller.view.zoom;
        _deferUserInteractionEndToAnimation = true;
        if (widget.onUserInteractionStart != null) {
          widget.onUserInteractionStart!.call();
        } else {
          widget.onUserInteraction?.call();
        }
        _animateZoomTo(
          zoom,
          (zoom * 0.5).clamp(_kMinZoom, _kMaxZoom),
          focalPoint: midpoint,
          onCompleted: () {
            _deferUserInteractionEndToAnimation = false;
            if (widget.onUserInteractionEnd != null) {
              widget.onUserInteractionEnd!.call();
            } else {
              widget.onUserInteraction?.call();
            }
          },
        );
        HapticFeedback.lightImpact();
      }
    }

    // Check single-finger double-tap (only when 1 finger remains)
    if (_activePointers.length == 1 && event is PointerUpEvent) {
      final now = DateTime.now();
      final prevAt = _lastRawTapAt;
      final prevPos = _lastRawTapPos;

      if (prevAt != null && prevPos != null) {
        final dtMs = now.difference(prevAt).inMilliseconds;
        final distPx = (event.localPosition - prevPos).distance;
        if (dtMs <= _kRawDoubleTapMaxGapMs &&
            distPx <= _kRawDoubleTapMaxDistancePx) {
          _triggerDoubleTapAt(event.localPosition);
          _lastRawTapAt = null;
          _lastRawTapPos = null;
        } else {
          _lastRawTapAt = now;
          _lastRawTapPos = event.localPosition;
        }
      } else {
        _lastRawTapAt = now;
        _lastRawTapPos = event.localPosition;
      }
    }

    _activePointers.remove(event.pointer);
    if (_activePointers.length < 2) {
      _twoFingerTapCandidate = false;
      _twoFingerTapDownPositions.clear();
      _twoFingerTapStartedAt = null;
    }
  }

  void _onPointerSignal(PointerSignalEvent event) {
    if (event is! PointerScrollEvent) return;
    final controller = context.read<FractalController>();
    final factor = math.exp(-event.scrollDelta.dy * 0.001);
    final targetZoom = controller.view.zoom * factor;
    _applyZoomAroundFocal(
      controller: controller,
      targetZoom: targetZoom,
      focalPoint: event.localPosition,
    );
    widget.onUserInteraction?.call();
  }

  void _animateZoomTo(
    double from,
    double to, {
    Offset? focalPoint,
    VoidCallback? onCompleted,
  }) {
    final controller = context.read<FractalController>();

    _zoomAnimation?.dispose();
    _zoomAnimation = AnimationController(
      duration: const Duration(milliseconds: 200),
      vsync: this as TickerProvider,
    );

    final tween = Tween<double>(begin: from, end: to);
    final curve =
        CurvedAnimation(parent: _zoomAnimation!, curve: Curves.easeOutCubic);
    _zoomAnimation!.addListener(() {
      final zoom = tween.transform(curve.value);
      if (focalPoint == null) {
        controller.updateZoom(zoom);
      } else {
        _applyZoomAroundFocal(
          controller: controller,
          targetZoom: zoom,
          focalPoint: focalPoint,
        );
      }
    });
    if (onCompleted != null) {
      _zoomAnimation!.addStatusListener((status) {
        if (status == AnimationStatus.completed) {
          onCompleted();
        }
      });
    }

    unawaited(_zoomAnimation!.forward());
  }

  /// Animates pan and zoom simultaneously from start values to target values.
  /// Simpler and more reliable than the incremental focal-point approach for
  /// gestures where the target is known up-front (e.g. double-tap).
  void _animatePanZoomTo({
    required Vector2 startPan,
    required Vector2 targetPan,
    required double fromZoom,
    required double toZoom,
    VoidCallback? onCompleted,
  }) {
    final controller = context.read<FractalController>();

    _zoomAnimation?.dispose();
    _zoomAnimation = AnimationController(
      duration: const Duration(milliseconds: 200),
      vsync: this as TickerProvider,
    );

    final curve =
        CurvedAnimation(parent: _zoomAnimation!, curve: Curves.easeOutCubic);
    _zoomAnimation!.addListener(() {
      final t = curve.value;
      controller.updateZoom(fromZoom + (toZoom - fromZoom) * t);
      controller.updatePan(Vector2(
        startPan.x + (targetPan.x - startPan.x) * t,
        startPan.y + (targetPan.y - startPan.y) * t,
      ));
    });
    if (onCompleted != null) {
      _zoomAnimation!.addStatusListener((status) {
        if (status == AnimationStatus.completed) {
          onCompleted();
        }
      });
    }

    unawaited(_zoomAnimation!.forward());
  }

  void _onLongPress(LongPressStartDetails details) {
    HapticFeedback.heavyImpact();
    AppLogger.instance.debug('gesture', 'long_press', data: {
      'x': details.localPosition.dx.toStringAsFixed(1),
      'y': details.localPosition.dy.toStringAsFixed(1),
    });
    _showContextMenu(details.globalPosition);
  }

  /// Called when user taps the left (Mandelbrot) panel of the julia_dual module.
  /// Converts screen position to Mandelbrot complex coords and updates Julia seed.
  void _onJuliaDualTap(Offset localPos, FractalController controller) {
    final renderBox = context.findRenderObject() as RenderBox?;
    if (renderBox == null) return;
    final size = renderBox.size;

    // Only respond to taps on the left (Mandelbrot) panel.
    if (localPos.dx >= size.width * 0.5) return;

    final view = controller.view;
    // Mirror the dual-panel shader's coordinate mapping exactly:
    //   halfW = uResolution.x * 0.5
    //   scale = min(halfW, uResolution.y)
    //   uv    = (fragCoord - vec2(halfW*0.5, uResolution.y*0.5)) / scale
    final halfW = size.width * 0.5;
    final scale = halfW < size.height ? halfW : size.height;
    final uvX = (localPos.dx - halfW * 0.5) / scale;
    final uvY = (localPos.dy - size.height * 0.5) / scale;

    // Apply zoom and pan to get fractal coordinates.
    final fracX = uvX / view.zoom + view.pan.x;
    final fracY = uvY / view.zoom + view.pan.y;

    controller.updateParam('juliaCReal', fracX.clamp(-2.0, 2.0));
    controller.updateParam('juliaCImag', fracY.clamp(-2.0, 2.0));
  }

  void _showContextMenu(Offset position) {
    final controller = context.read<FractalController>();
    final l10n = AppLocalizations.of(context);
    if (l10n == null) return;

    showMenu<String>(
      context: context,
      position: RelativeRect.fromLTRB(
        position.dx,
        position.dy,
        position.dx + 1,
        position.dy + 1,
      ),
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(12),
      ),
      items: [
        PopupMenuItem<String>(
          value: 'reset',
          child: Row(
            children: [
              const Icon(Icons.refresh_rounded, size: 20),
              const SizedBox(width: 12),
              Text(l10n.contextMenuResetView),
            ],
          ),
        ),
        const PopupMenuDivider(),
        PopupMenuItem<String>(
          value: 'controls',
          child: Row(
            children: [
              const Icon(Icons.tune_rounded, size: 20),
              const SizedBox(width: 12),
              Text(l10n.contextMenuOpenControls),
            ],
          ),
        ),
        PopupMenuItem<String>(
          value: 'presets',
          child: Row(
            children: [
              const Icon(Icons.bookmark_rounded, size: 20),
              const SizedBox(width: 12),
              Text(l10n.contextMenuOpenPresets),
            ],
          ),
        ),
        PopupMenuItem<String>(
          value: 'randomize',
          child: Row(
            children: [
              const Icon(Icons.shuffle_rounded, size: 20),
              const SizedBox(width: 12),
              Text(l10n.contextMenuRandomize),
            ],
          ),
        ),
        const PopupMenuDivider(),
        PopupMenuItem<String>(
          value: 'export',
          child: Row(
            children: [
              const Icon(Icons.download_rounded, size: 20),
              const SizedBox(width: 12),
              Text(l10n.contextMenuExport),
            ],
          ),
        ),
      ],
    ).then((value) {
      if (value == null) return;

      switch (value) {
        case 'reset':
          controller.resetView();
          HapticFeedback.mediumImpact();
          break;
        case 'controls':
          widget.onOpenControls?.call();
          break;
        case 'presets':
          widget.onOpenPresets?.call();
          break;
        case 'randomize':
          controller.randomizeParams();
          HapticFeedback.mediumImpact();
          break;
        case 'export':
          widget.onOpenExport?.call();
          break;
      }
    });
  }
}

